import React from 'react';
import { Card, Stack, Text, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getConditionIcon = (condition: string): string => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun')) return '☀️';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('drizzle')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('mist') || normalized.includes('fog')) return '🌫️';
  if (normalized.includes('wind')) return '💨';
  return '🌤️';
};

export default function GeneratedComponent({
  city = '—',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const displayUnit = unit || 'C';
  const conditionIcon = getConditionIcon(condition);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      radius="lg"
      border
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack gap="var(--ggui-spacing-1, 4px)">
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            as="div"
          >
            {city}
          </Text>
          <Stack direction="horizontal" align="end" gap="var(--ggui-spacing-2, 8px)">
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
              as="div"
            >
              {temperature}°{displayUnit}
            </Text>
            <Text
              variant="bodyLarge"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="div"
            >
              {conditionIcon} {condition}
            </Text>
          </Stack>
        </Stack>

        <Stack direction="horizontal" justify="between" gap="var(--ggui-spacing-4, 16px)">
          <Box
            padding="var(--ggui-spacing-2, 8px)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Box>

          <Box
            padding="var(--ggui-spacing-2, 8px)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Box
          padding="var(--ggui-spacing-2, 8px)"
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-md, 8px)"
        >
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              5-Day Forecast
            </Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" justify="between" wrap>
              {forecast.map((item, index) => (
                <Box
                  key={`${item.day ?? 'day'}-${index}`}
                  padding="var(--ggui-spacing-2, 8px)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-sm, 4px)"
                >
                  <Stack align="center" gap={2}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.day ?? '—'}
                    </Text>
                    <Text variant="body" as="div" color="var(--ggui-color-onSurface, #18181b)">
                      {item.icon ?? '🌤️'}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                      {item.high ?? '—'}° / {item.low ?? '—'}°
                    </Text>
                  </Stack>
                </Box>
              ))}
            </Stack>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionCategory(condition: string): 'warning' | 'default' | 'info' | 'primary' | 'error' {
  const c = condition.toLowerCase();
  if (c.includes('severe') || c.includes('extreme') || c.includes('tornado') || c.includes('hurricane')) return 'error';
  if (c.includes('sunny') || c.includes('clear')) return 'warning';
  if (c.includes('cloud') || c.includes('fog') || c.includes('mist') || c.includes('haze')) return 'default';
  if (c.includes('rain') || c.includes('shower') || c.includes('drizzle') || c.includes('storm') || c.includes('thunder')) return 'info';
  if (c.includes('snow') || c.includes('sleet') || c.includes('ice')) return 'primary';
  return 'primary';
}

function getConditionIcon(condition: string): string {
  const c = condition.toLowerCase();
  if (c.includes('sunny') || c.includes('clear')) return '☀️';
  if (c.includes('partly cloudy')) return '⛅';
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('shower') || c.includes('drizzle')) return '🌧️';
  if (c.includes('thunder') || c.includes('storm')) return '⛈️';
  if (c.includes('snow')) return '❄️';
  if (c.includes('wind')) return '💨';
  if (c.includes('fog') || c.includes('mist') || c.includes('haze')) return '🌫️';
  return '🌤️';
}

export default function GeneratedComponent({
  city = 'Sample City',
  temperature = 24,
  condition = 'Sunny',
  humidity = 48,
  windSpeed = 10,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 28, low: 20 },
    { day: 'Tue', icon: '⛅', high: 26, low: 19 },
    { day: 'Wed', icon: '🌧️', high: 23, low: 17 },
    { day: 'Thu', icon: '☁️', high: 24, low: 18 },
    { day: 'Fri', icon: '☀️', high: 29, low: 21 },
  ],
}: Props) {
  const normalizedUnit = unit || 'C';
  const currentIcon = getConditionIcon(condition);
  const conditionVariant = getConditionCategory(condition);

  return (
    <Card
      shadow="md"
      radius="xl"
      border
      padding="var(--ggui-spacing-6, 24px)"
      aria-label={`Weather in ${city}`}
    >
      <Stack direction="vertical" gap="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between" align="start" wrap>
          <Stack direction="vertical" gap="var(--ggui-spacing-2, 8px)">
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text
              variant="body"
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {temperature}°{normalizedUnit}
            </Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
              <Badge variant={conditionVariant} size="sm">
                {condition}
              </Badge>
            </Stack>
          </Stack>

          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-container, #ede9fe)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Text
              as="span"
              size="4xl"
              color="var(--ggui-color-onContainer, #4c1d95)"
              aria-hidden="true"
            >
              {currentIcon}
            </Text>
          </Box>
        </Stack>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          <Box
            padding="var(--ggui-spacing-2, 8px)"
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="label" color="var(--ggui-color-info-500, #06b6d4)">
                {humidity}%
              </Text>
            </Stack>
          </Box>

          <Box
            padding="var(--ggui-spacing-2, 8px)"
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <Box
          padding="var(--ggui-spacing-2, 8px)"
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" justify="between" wrap>
            {forecast.map((item, index) => (
              <Box
                key={`${item.day ?? 'day'}-${index}`}
                padding="var(--ggui-spacing-2, 8px)"
                background="var(--ggui-color-surface, #fafafa)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)" align="center">
                  <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.day ?? '—'}
                  </Text>
                  <Text as="span" size="xl" aria-hidden="true">
                    {item.icon ?? '—'}
                  </Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      {item.high !== undefined ? `${item.high}°` : '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.low !== undefined ? `${item.low}°` : '—'}
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Box, Card, Divider, Heading, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = 'Tokyo',
  temperature = 28,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 8,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 30, low: 22 },
    { day: 'Tue', icon: '⛅', high: 27, low: 20 },
    { day: 'Wed', icon: '☁️', high: 25, low: 19 },
    { day: 'Thu', icon: '🌧️', high: 23, low: 18 },
    { day: 'Fri', icon: '🌤️', high: 29, low: 21 },
  ],
}: Props) {
  const safeUnit = unit ?? 'C';

  const resolveConditionIcon = (value: string): string => {
    const normalized = value.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (
      normalized.includes('partly cloudy') ||
      normalized.includes('partly sunny') ||
      normalized.includes('cloudy')
    )
      return '⛅';
    if (normalized.includes('rain') || normalized.includes('showers')) return '🌧️';
    if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
    if (normalized.includes('snow')) return '❄️';
    if (normalized.includes('mist') || normalized.includes('fog') || normalized.includes('haze'))
      return '🌫️';
    return '🌤️';
  };

  const mainIcon = resolveConditionIcon(condition);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      radius="xl"
      border
      role="region"
      aria-label={`Weather in ${city}`}
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="start" wrap>
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Weather
            </Text>
            <Heading
              level={4}
              color="var(--ggui-color-onSurface, #18181b)"
              align="left"
              // @ts-expect-error - title is supported by native attributes passthrough in runtime
              title={city}
            >
              {city}
            </Heading>
            <Stack direction="horizontal" align="end" gap="var(--ggui-spacing-2, 8px)">
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                {temperature}°
              </Text>
              <Text
                variant="bodyLarge"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {safeUnit}
              </Text>
            </Stack>
            <Text
              variant="bodyLarge"
              weight="medium"
              color="var(--ggui-color-primary-700, #0369a1)"
            >
              {condition}
            </Text>
          </Stack>

          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-container, #ede9fe)"
            borderRadius="var(--ggui-shape-radius-xl, 16px)"
          >
            <Text
              as="span"
              size="4xl"
              color="var(--ggui-color-onContainer, #4c1d95)"
              // @ts-expect-error - aria-hidden passthrough supported at runtime
              aria-hidden="true"
            >
              {mainIcon}
            </Text>
          </Box>
        </Stack>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            // @ts-expect-error native style passthrough
            style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', minWidth: 140 }}
          >
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Box>

          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            // @ts-expect-error native style passthrough
            style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', minWidth: 140 }}
          >
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind Speed
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed}
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          justify="between"
          wrap
          // @ts-expect-error aria-label passthrough
          aria-label="5-day forecast"
        >
          {forecast.map((item, index) => {
            const dayValue = item.day ?? '—';
            const iconValue = item.icon ?? resolveConditionIcon(condition) ?? '•';
            const highValue = typeof item.high === 'number' ? `${item.high}°${safeUnit}` : '—';
            const lowValue = typeof item.low === 'number' ? `${item.low}°${safeUnit}` : '—';

            return (
              <Box
                key={item.day ?? index}
                padding="var(--ggui-spacing-2, 8px)"
                background="var(--ggui-color-surface, #fafafa)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                // @ts-expect-error native style passthrough
                style={{
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  minWidth: 84,
                  flex: '1 1 84px',
                }}
              >
                <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {dayValue}
                  </Text>
                  <Text
                    variant="bodyLarge"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    // @ts-expect-error aria-hidden passthrough
                    aria-hidden="true"
                  >
                    {iconValue}
                  </Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                    <Text
                      variant="bodySmall"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {highValue}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {lowValue}
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Card>
  );
}

import * as React from 'react';
import { 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Divider, 
  Box 
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

/**
 * WeatherCard displays current weather information and a 5-day forecast.
 * Built with theme-aware GGUI primitives and CSS variables.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  // Helper to get emoji for common weather conditions
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅';
  };

  return (
    <Card 
      padding={0} 
      shadow="md" 
      radius="xl"
      border={true}
    >
      <Stack gap={0}>
        {/* Current Weather Section */}
        <Box 
          padding={24} 
          background="var(--ggui-color-surface, #ffffff)"
          borderRadius="var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px) 0 0"
        >
          <Stack gap={24}>
            {/* Header: City and Status Badge */}
            <Stack direction="horizontal" justify="between" align="start">
              <Stack gap={4}>
                <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                  {city}
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Weather Update
                </Text>
              </Stack>
              <Box 
                paddingX={12} 
                paddingY={4} 
                background="var(--ggui-color-primary-50, #f0f9ff)" 
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
              >
                <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">
                  {condition}
                </Text>
              </Box>
            </Stack>

            {/* Display Temperature and Icon */}
            <Stack direction="horizontal" align="center" gap={24}>
              <Text size="4xl">
                {getConditionEmoji(condition)}
              </Text>
              <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
                {temperature}°{unit}
              </Heading>
            </Stack>

            {/* Details Strip (Humidity, Wind) */}
            <Stack direction="horizontal" gap={32}>
              <Stack direction="horizontal" gap={12} align="center">
                <Box padding={8} background="var(--ggui-color-neutral-100, #f3f4f6)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Text size="sm">💧</Text>
                </Box>
                <Stack gap={0}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Humidity
                  </Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {humidity}%
                  </Text>
                </Stack>
              </Stack>
              <Stack direction="horizontal" gap={12} align="center">
                <Box padding={8} background="var(--ggui-color-neutral-100, #f3f4f6)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Text size="sm">🌬️</Text>
                </Box>
                <Stack gap={0}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Wind
                  </Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {windSpeed} km/h
                  </Text>
                </Stack>
              </Stack>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Stripe */}
        <Box 
          padding={20} 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="0 0 var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px)"
        >
          <Stack direction="horizontal" justify="between" align="center">
            {forecast.map((item, index) => (
              <Stack key={item.day || index} align="center" gap={8} style={{ flex: 1 }}>
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day}
