            <Stack align="center" gap={4}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text weight="semibold" size="lg" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} <Text as="span" variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{speedUnit}</Text>
