        <Stack direction="horizontal" justify="between" align="stretch" wrap={true}>
          {forecast.map((item, index) => (
            <Stack 
              key={`${item.day}-${index}`} 
              align="center" 
              gap={8} 
              style={{ flex: '1 1 0', minWidth: '60px', padding: 'var(--ggui-spacing-1, 4px)' }}
