  if (c.includes('cloud') || c.includes('overcast')) return '☁️';
  if (c.includes('rain') || c.includes('shower') || c.includes('drizzle')) return '🌧️';
  if (c.includes('thunder') || c.includes('storm')) return '⛈️';
  if (c.includes('snow') || c.includes('blizzard')) return '❄️';
  if (c.includes('fog') || c.includes('mist') || c.includes('haze')) return '🌫️';
  if (c.includes('wind') || c.includes('breezy')) return '💨';
  return '🌤️';
}

function getConditionBadgeVariant(
  condition: string
): 'primary' | 'info' | 'warning' | 'error' | 'default' {
  const c = condition.toLowerCase();
  if (c.includes('sunny') || c.includes('clear')) return 'warning';
  if (c.includes('rain') || c.includes('shower') || c.includes('drizzle')) return 'info';
  if (c.includes('thunder') || c.includes('storm')) return 'error';
  if (c.includes('snow') || c.includes('blizzard')) return 'primary';
  return 'default';
}

